sys_script.script:
/**
 * Before Insert/Update: Auto-sets escalation_level based on priority.
 * Never downgrades an existing escalation.
 *
 * Priority mapping:
 *   1 (Critical) -> tier_2 minimum
 *   2 (High) -> tier_1 minimum
 *   3-5 (Moderate/Low) -> no change
 *
 * Globals: current, previous, gs
 */
(function executeRule(current, previous) {
    var priority = parseInt(current.getValue('priority'), 10) || 4;
    var currentEscalation = current.getValue('escalation_level') || 'none';

    // Define escalation hierarchy (index = severity rank, higher = more severe)
    var hierarchy = ['none', 'tier_1', 'tier_2', 'tier_3', 'management'];
    var currentRank = hierarchy.indexOf(currentEscalation);
    if (currentRank < 0) {
        currentRank = 0;
    }

    var requiredRank = 0;
    if (priority == 1) {
        requiredRank = 2; // tier_2
    } else if (priority == 2) {
        requiredRank = 1; // tier_1
    }

    // Only escalate UP, never down
    if (requiredRank > currentRank) {
        current.setValue('escalation_level', hierarchy[requiredRank]);
    }
})(current, previous);
